head.script:
//
  (function(){
    try {
      var s = localStorage.getItem('theme');
      var d = window.matchMedia && window.matchMedia('(prefers-color-scheme: dark)').matches;
      document.documentElement.setAttribute('data-theme', s || (d ? 'dark' : 'light'));
    } catch(e){}
  })();
//

head.b:skin:
  :root, [data-theme="dark"] {
    --bg: #0b0c10;
    --bg-elevated: #15161a;
    --surface: rgba(28, 30, 36, 0.6);
    --surface-solid: #1c1e24;
    --border: rgba(255,255,255,0.06);
    --border-solid: #2f3542;
    --accent: #00d2d3;
    --accent-hover: #01a3a4;
    --text: #f1f2f6;
    --text-secondary: #a4b0be;
    --text-muted: #747d8c;
    --glass-bg: rgba(21, 22, 26, 0.75);
    --glass-soft-bg: rgba(28, 30, 36, 0.5);
    --radius-sm: 10px;
    --radius-md: 14px;
    --radius-lg: 18px;
    --radius-xl: 24px;
    --shadow: 0 8px 32px rgba(0,0,0,0.35);
    --shadow-lg: 0 20px 60px rgba(0,0,0,0.5);
    --transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
    --font: 'Inter', -apple-system, BlinkMacSystemFont, sans-serif;
    --font-hi: 'Noto Sans Devanagari', 'Inter', sans-serif;
    --container: 1400px;
  }
  [data-theme="light"] {
    --bg: #f8f9fa;
    --bg-elevated: #ffffff;
    --surface: rgba(255, 255, 255, 0.6);
    --surface-solid: #ffffff;
    --border: rgba(0,0,0,0.08);
    --border-solid: #dcdde1;
    --accent: #0097e6;
    --accent-hover: #00a8ff;
    --text: #2f3640;
    --text-secondary: #718093;
    --text-muted: #a4b0be;
    --glass-bg: rgba(255, 255, 255, 0.75);
    --glass-soft-bg: rgba(255, 255, 255, 0.5);
    --shadow: 0 8px 32px rgba(0,0,0,0.05);
    --shadow-lg: 0 20px 60px rgba(0,0,0,0.1);
  }

  /* ---- Hindi font override ---- */
  [data-lang="hi"] {
    font-family: var(--font-hi);
  }
  [data-lang="hi"] .brand-text,
  [data-lang="hi"] .main-nav a,
  [data-lang="hi"] .section-heading,
  [data-lang="hi"] .detail-title,
  [data-lang="hi"] .detail-body,
  [data-lang="hi"] .meta-item,
  [data-lang="hi"] .card-title,
  [data-lang="hi"] .hero-title,
  [data-lang="hi"] .loader-text,
  [data-lang="hi"] .footer-copy,
  [data-lang="hi"] .header-search input {
    font-family: var(--font-hi);
  }
  /* Active lang indicator */
  #langBtn.lang-hi {
    color: var(--accent);
    border-color: var(--accent);
  }
  #langBtn .lang-tag {
    font-size: 0.6rem;
    font-weight: 700;
    line-height: 1;
    letter-spacing: 0.04em;
    margin-top: 2px;
    opacity: 0.8;
  }

  * { margin: 0; padding: 0; box-sizing: border-box; }
  html { scroll-behavior: smooth; }
  body {
    font-family: var(--font);
    background: var(--bg);
    color: var(--text);
    line-height: 1.5;
    -webkit-font-smoothing: antialiased;
    overflow-x: hidden;
  }
  a { text-decoration: none; color: inherit; transition: var(--transition); }
  img { max-width: 100%; height: auto; display: block; }
  .material-icons { vertical-align: middle; font-size: 1.1em; line-height: 1; }

  .glass {
    background: var(--glass-bg);
    backdrop-filter: blur(20px) saturate(1.4);
    -webkit-backdrop-filter: blur(20px) saturate(1.4);
    border: 1px solid var(--border);
  }
  .glass-soft {
    background: var(--glass-soft-bg);
    backdrop-filter: blur(16px);
    -webkit-backdrop-filter: blur(16px);
    border: 1px solid var(--border);
  }

  .container { width: 100%; max-width: var(--container); margin: 0 auto; padding: 0 24px; }

  .site-header {
    position: sticky;
    top: 0;
    z-index: 1000;
    border-bottom: 1px solid var(--border);
  }
  .header-inner {
    display: flex;
    align-items: center;
    justify-content: space-between;
    height: 68px;
    gap: 20px;
  }
  .brand {
    display: flex;
    align-items: center;
    gap: 10px;
    font-size: 1.35rem;
    font-weight: 800;
    color: var(--text);
    letter-spacing: -0.5px;
    flex-shrink: 0;
  }
  .brand .material-icons, .brand .material-symbols-outlined { font-size: 1.5rem; color: var(--accent); }
  .main-nav {
    display: flex;
    align-items: center;
    gap: 6px;
  }
  .main-nav .section,
  .main-nav .widget {
    display: contents;
  }
  .main-nav a {
    display: flex;
    align-items: center;
    gap: 6px;
    padding: 8px 16px;
    border-radius: var(--radius-sm);
    color: var(--text-secondary);
    font-size: 0.88rem;
    font-weight: 500;
    transition: var(--transition);
  }
  .main-nav a:hover {
    background: rgba(255,255,255,0.05);
    color: var(--text);
  }

  .header-search {
    position: relative;
    width: 340px;
    max-width: 100%;
  }
  .header-search form {
    display: flex;
    align-items: center;
    background: rgba(255,255,255,0.04);
    border: 1px solid var(--border);
    border-radius: 999px;
    overflow: hidden;
    transition: var(--transition);
  }
  .header-search form:focus-within {
    background: rgba(255,255,255,0.07);
    border-color: rgba(0, 210, 211, 0.3);
    box-shadow: 0 0 0 3px rgba(0, 210, 211, 0.08);
  }
  .header-search input {
    flex: 1;
    background: transparent;
    border: none;
    padding: 10px 18px;
    color: var(--text);
    font-family: var(--font);
    font-size: 0.88rem;
    outline: none;
  }
  .header-search input::placeholder { color: var(--text-muted); }
  .header-search button {
    background: none;
    border: none;
    color: var(--text-muted);
    padding: 0 16px;
    cursor: pointer;
    display: flex;
    align-items: center;
    transition: var(--transition);
  }
  .header-search button:hover { color: var(--accent); }

  .header-actions { display: flex; align-items: center; gap: 8px; }
  .icon-btn {
    background: transparent; border: 1px solid var(--border); color: var(--text);
    width: 42px; height: 42px; border-radius: 50%;
    display: flex; flex-direction: column; align-items: center; justify-content: center;
    cursor: pointer; transition: var(--transition);
  }
  .icon-btn:hover {
    background: var(--surface-solid); color: var(--accent); border-color: var(--accent);
  }
  .menu-toggle {
    display: none;
  }

  .site-main { min-height: calc(100vh - 68px - 80px); padding: 28px 0; }

  .page-header {
    margin-bottom: 28px;
    display: flex;
    align-items: flex-end;
    justify-content: space-between;
    gap: 16px;
    flex-wrap: wrap;
  }
  .page-title {
    font-size: 1.7rem;
    font-weight: 800;
    display: flex;
    align-items: center;
    gap: 10px;
    letter-spacing: -0.3px;
  }
  .page-title .material-icons { color: var(--accent); font-size: 1.5rem; margin-top: 6px; }

  .hero-carousel { margin-bottom: 32px; padding: 20px 0; }
  .hero-carousel .splide__slide {
    transition: opacity 0.6s ease, transform 0.6s ease, filter 0.6s ease;
    opacity: 0.35;
    filter: blur(4px);
    transform: scale(0.85);
  }
  .hero-carousel .splide__slide.is-active { opacity: 1; filter: blur(0); transform: scale(1); z-index: 2; }
  .hero-slide-link { display: block; position: relative; aspect-ratio: 2 / 3; border-radius: var(--radius-md); overflow: hidden; box-shadow: var(--shadow); height: 100%; }
  .hero-slide-link img { width: 100%; height: 100%; object-fit: cover; transition: transform 0.5s ease; }
  .hero-slide-link:hover img { transform: scale(1.06); }
  .hero-overlay { position: absolute; inset: 0; background: linear-gradient(to top, rgba(0,0,0,0.9) 0%, transparent 60%); display: flex; align-items: flex-end; padding: 16px; color: #fff; }
  .hero-title { font-size: 1rem; font-weight: 700; margin: 0; display: -webkit-box; -webkit-line-clamp: 2; -webkit-box-orient: vertical; overflow: hidden; text-shadow: 0 2px 4px rgba(0,0,0,0.8); }

  .section-divider {
    height: 1px;
    background: var(--border);
    margin: 0 0 28px 0;
    width: 100%;
  }
  .section-heading {
    font-size: 1.5rem;
    font-weight: 800;
    margin-bottom: 24px;
    display: flex;
    align-items: center;
    gap: 10px;
    color: var(--text);
  }
  .section-heading .material-icons { color: var(--accent); font-size: 1.6rem; }

  .empty-state {
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    text-align: center;
    padding: 80px 24px;
    min-height: 400px;
  }
  .empty-state > .material-icons {
    font-size: 4.5rem;
    color: var(--text-muted);
    opacity: 0.6;
    margin-bottom: 20px;
  }
  .empty-title {
    font-size: 1.4rem;
    font-weight: 700;
    color: var(--text);
    margin-bottom: 8px;
  }
  .empty-desc {
    font-size: 0.95rem;
    color: var(--text-secondary);
    max-width: 400px;
    margin-bottom: 24px;
    line-height: 1.6;
  }
  .empty-btn {
    display: inline-flex;
    align-items: center;
    gap: 8px;
    background: var(--accent);
    color: #000;
    padding: 12px 24px;
    border-radius: 999px;
    font-weight: 600;
    font-size: 0.9rem;
    transition: var(--transition);
  }
  .empty-btn:hover {
    background: var(--accent-hover);
    transform: translateY(-2px);
    box-shadow: 0 4px 16px rgba(0,210,211,0.3);
  }

  .book-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(160px, 1fr));
    gap: 20px;
  }
  .book-card {
    background: transparent;
    border-radius: 0;
    transition: var(--transition);
    border: none;
    position: relative;
  }
  .book-card:hover {
    transform: translateY(-4px);
  }
  .card-link { display: block; }
  .card-image {
    position: relative;
    aspect-ratio: 2 / 3;
    overflow: hidden;
    background: var(--bg-elevated);
    border-radius: var(--radius-md);
    border: 1px solid var(--border);
    box-shadow: var(--shadow);
    transition: var(--transition);
  }
  .card-image img {
    width: 100%;
    height: 100%;
    object-fit: cover;
    transition: transform 0.5s cubic-bezier(0.4, 0, 0.2, 1);
  }
  .book-card:hover .card-image { border-color: var(--accent); box-shadow: var(--shadow-lg); }
  .book-card:hover .card-image img { transform: scale(1.08); }
  .card-overlay {
    position: absolute;
    inset: 0;
    display: flex;
    flex-direction: column;
    justify-content: flex-end;
    padding: 16px;
    background: linear-gradient(to top, rgba(0,0,0,0.9) 0%, transparent 60%);
    transition: background 0.3s ease;
  }
  .book-card:hover .card-overlay {
    background: linear-gradient(to top, rgba(0,0,0,0.95) 0%, rgba(0,0,0,0.3) 100%);
  }
  .card-badge {
    position: absolute;
    top: 10px;
    right: 10px;
    background: var(--surface);
    color: var(--text);
    font-size: 0.72rem;
    font-weight: 700;
    padding: 4px 10px;
    border-radius: 999px;
    text-transform: uppercase;
    letter-spacing: 0.5px;
    box-shadow: 0 2px 8px rgba(0,0,0,0.3);
  }
  .card-badge[data-label="Non Fiksi"],
  .card-badge[data-label="Non-Fiksi"],
  .card-badge[data-label="Nonfiksi"],
  .card-badge[data-label="non fiksi"],
  .card-badge[data-label="non-fiksi"],
  .card-badge[data-label="nonfiksi"] {
    background: #00a8ff;
    color: #fff;
  }
  .card-badge[data-label="Fiksi"],
  .card-badge[data-label="fiksi"],
  .card-badge[data-label="FIKSI"] {
    background: #ff4757;
    color: #fff;
  }
  .card-title {
    font-size: 0.95rem;
    font-weight: 700;
    line-height: 1.35;
    margin: 0;
    display: -webkit-box;
    -webkit-line-clamp: 2;
    -webkit-box-orient: vertical;
    overflow: hidden;
    color: #fff;
    text-shadow: 0 2px 4px rgba(0,0,0,0.8);
    transition: transform 0.3s ease;
  }
  .book-card:hover .card-title { transform: translateY(-4px); }
  .card-meta {
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: 6px;
  }
  .pill-soft {
    background: var(--surface);
    border: 1px solid var(--border);
    padding: 3px 10px;
    border-radius: 999px;
    font-size: 0.72rem;
    font-weight: 600;
    color: var(--text-secondary);
    text-transform: uppercase;
    letter-spacing: 0.3px;
    max-width: 100%;
  }
  .card-year {
    font-size: 0.78rem;
    color: var(--text-muted);
    font-weight: 500;
    white-space: nowrap;
  }

  .book-detail {
    background: var(--bg-elevated);
    border-radius: var(--radius-xl);
    border: 1px solid var(--border);
    overflow: hidden;
  }
  .detail-grid {
    display: grid;
    grid-template-columns: 280px 1fr;
    gap: 48px;
    padding: 48px;
  }
  .detail-cover { position: relative; flex-shrink: 0; }
  .detail-cover img {
    width: 100%;
    aspect-ratio: 2 / 3;
    object-fit: cover;
    border-radius: var(--radius-lg);
    box-shadow: var(--shadow-lg);
    border: 1px solid var(--border);
  }
  .detail-content { display: flex; flex-direction: column; gap: 24px; }
  .detail-header { margin-bottom: 4px; }
  .detail-title {
    font-size: 2.4rem;
    font-weight: 800;
    line-height: 1.15;
    margin-bottom: 10px;
    letter-spacing: -0.5px;
  }
  .detail-subtitle {
    font-size: 1.05rem;
    color: var(--text-secondary);
    font-weight: 400;
  }
  .detail-meta-bar {
    display: flex;
    flex-wrap: wrap;
    gap: 20px;
    padding: 20px 0;
    border-top: 1px solid var(--border);
    border-bottom: 1px solid var(--border);
  }
  .meta-item {
    display: flex;
    align-items: center;
    gap: 8px;
    font-size: 0.9rem;
    color: var(--text-secondary);
  }
  .meta-item .material-icons { font-size: 1.1rem; color: var(--accent); }
  .meta-item strong { color: var(--text); font-weight: 600; }
  .detail-labels { display: flex; flex-wrap: wrap; gap: 8px; }
  .label-tag {
    display: inline-flex;
    align-items: center;
    gap: 5px;
    padding: 6px 14px;
    background: rgba(255,255,255,0.05);
    border: 1px solid var(--border);
    border-radius: 999px;
    font-size: 0.8rem;
    font-weight: 500;
    color: var(--text-secondary);
    transition: var(--transition);
  }
  .label-tag:hover {
    background: var(--accent);
    color: #000;
    border-color: var(--accent);
  }
  .label-tag[data-label="Non Fiksi"],
  .label-tag[data-label="Non-Fiksi"],
  .label-tag[data-label="Nonfiksi"],
  .label-tag[data-label="non fiksi"],
  .label-tag[data-label="nonfiksi"] {
    border-color: #00a8ff;
    color: #00a8ff;
  }
  .label-tag[data-label="Fiksi"],
  .label-tag[data-label="fiksi"] {
    border-color: #ff4757;
    color: #ff4757;
  }
  .detail-body {
    font-size: 1rem;
    line-height: 1.85;
    color: var(--text-secondary);
  }
  .detail-body h2, .detail-body h3, .detail-body h4 {
    color: var(--text);
    margin: 28px 0 14px;
    display: flex;
    align-items: center;
    gap: 8px;
    font-weight: 700;
  }
  .detail-body h3 { font-size: 1.15rem; }
  .detail-body h3 .material-icons { color: var(--accent); font-size: 1.2rem; }
  .detail-body p { margin-bottom: 16px; }
  .detail-body img { border-radius: var(--radius-md); margin: 16px 0; border: 1px solid var(--border); }
  .detail-body blockquote {
    border-left: 3px solid var(--accent);
    padding-left: 20px;
    margin: 20px 0;
    color: var(--text-muted);
    font-style: italic;
  }
  .detail-body table {
    width: 100%;
    border-collapse: collapse;
    margin: 20px 0;
    font-size: 0.9rem;
    border: 1px solid var(--border);
    border-radius: var(--radius-md);
    overflow: hidden;
  }
  .detail-body th, .detail-body td {
    padding: 12px 16px;
    text-align: left;
    border-bottom: 1px solid var(--border);
  }
  .detail-body th {
    background: var(--surface-solid);
    color: var(--text);
    font-weight: 600;
    width: 28%;
  }
  .detail-body tr:last-child td { border-bottom: none; }
  .detail-body tr:hover td { background: rgba(255,255,255,0.02); }

  .book-detail .detail-body img:first-of-type { display: none; }

  .static-page {
    background: var(--bg-elevated);
    border-radius: var(--radius-xl);
    border: 1px solid var(--border);
    padding: 48px;
    max-width: 800px;
    margin: 0 auto;
  }
  .static-page h1 {
    font-size: 1.9rem;
    margin-bottom: 24px;
    display: flex;
    align-items: center;
    gap: 10px;
    font-weight: 800;
  }
  .static-page h1 .material-icons { color: var(--accent); }

  .pagination {
    display: flex;
    justify-content: center;
    align-items: center;
    gap: 6px;
    margin-top: 48px;
    padding-top: 28px;
    border-top: 1px solid var(--border);
  }
  .pagination a, .pagination span {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    min-width: 40px;
    height: 40px;
    padding: 0 12px;
    border-radius: var(--radius-sm);
    font-size: 0.88rem;
    font-weight: 500;
    transition: var(--transition);
  }
  .pagination a {
    background: var(--surface-solid);
    color: var(--text-secondary);
    border: 1px solid var(--border);
  }
  .pagination a:hover {
    background: var(--accent);
    color: #000;
    border-color: var(--accent);
  }
  .pagination .current {
    background: var(--accent);
    color: #000;
    font-weight: 700;
    border: 1px solid var(--accent);
  }
  .pagination .page-dots {
    background: transparent; border: none; min-width: auto; padding: 0 4px; color: var(--text-muted);
  }

  .site-footer { margin-top: 56px; padding: 24px 0; }
  .footer-box { border-radius: var(--radius-xl); padding: 24px 32px; }
  .footer-inner {
    display: flex;
    justify-content: space-between;
    align-items: center;
    flex-wrap: wrap;
    gap: 16px;
  }
  .footer-copy { font-size: 0.82rem; color: var(--text-muted); line-height: 1.6; max-width: 600px; }
  .social ul { list-style: none; display: flex; align-items: center; gap: 12px; margin: 0; padding: 0; }
  .social a { display: flex; align-items: center; justify-content: center; width: 36px; height: 36px; border-radius: 50%; background: var(--surface-solid); border: 1px solid var(--border); color: var(--text-muted); transition: var(--transition); }
  .social a:hover { color: var(--accent); border-color: var(--accent); }
  .social svg { fill: currentColor; }
  .sr-only { position: absolute; width: 1px; height: 1px; padding: 0; margin: -1px; overflow: hidden; clip: rect(0,0,0,0); border: 0; }

  .widget-area {
    background: var(--bg-elevated);
    border: 1px dashed var(--border-solid);
    border-radius: var(--radius-md);
    padding: 24px;
    margin: 24px 0;
  }
  .widget-area h2 {
    font-size: 0.9rem;
    color: var(--text-muted);
    margin-bottom: 16px;
    text-transform: uppercase;
    letter-spacing: 1px;
  }

  @media (max-width: 1024px) {
    .detail-grid { grid-template-columns: 240px 1fr; gap: 32px; padding: 32px; }
    .book-grid { grid-template-columns: repeat(auto-fill, minmax(140px, 1fr)); gap: 16px; }
    .header-search { width: 260px; }
  }
  @media (max-width: 768px) {
    .header-inner { height: 60px; gap: 12px; }
    .brand-text { display: none; }
    .main-nav { display: none; position: absolute; top: 60px; left: 0; right: 0; background: var(--bg-elevated); border-bottom: 1px solid var(--border); padding: 12px 24px; flex-direction: column; gap: 4px; z-index: 999; }
    .main-nav.active { display: flex; }
    .main-nav a { width: 100%; padding: 10px 14px; }
    .menu-toggle { display: flex; }
    .header-search { width: auto; flex: 1; }
    .detail-grid { grid-template-columns: 1fr; padding: 24px; }
    .hero-carousel { margin-bottom: 20px; }
    .hero-overlay { padding: 12px; }
    .hero-title { font-size: 0.85rem; }
    .section-heading { font-size: 1.3rem; margin-bottom: 20px; }
    .detail-cover { max-width: 240px; margin: 0 auto; }
    .detail-title { font-size: 1.7rem; }
    .detail-meta-bar { flex-direction: column; gap: 12px; padding: 16px 0; }
    .book-grid { grid-template-columns: repeat(auto-fill, minmax(120px, 1fr)); gap: 12px; }
    .page-title { font-size: 1.4rem; }
    .static-page { padding: 28px; }
    .footer-inner { flex-direction: column; text-align: center; }
  }
  @media (max-width: 480px) {
    .book-grid { grid-template-columns: repeat(2, 1fr); gap: 10px; }
    .card-title { font-size: 0.85rem; }
    .card-overlay { padding: 12px; }
    .container { padding: 0 16px; }
    .detail-grid { padding: 16px; gap: 20px; }
    .detail-title { font-size: 1.4rem; }
    .icon-btn { width: 36px; height: 36px; }
    .header-search input { padding: 8px 14px; font-size: 0.8rem; }
    .header-search button { padding: 0 12px; }
  }

  .loader-overlay {
    position: fixed; inset: 0; background: var(--bg);
    z-index: 9999; display: flex; align-items: center; justify-content: center;
    transition: opacity 0.4s ease;
  }
  .loader-overlay.hide { opacity: 0; pointer-events: none; }
  .loader-card {
    padding: 32px 48px; border-radius: var(--radius-lg);
    display: flex; flex-direction: column; align-items: center; gap: 20px;
  }
  .loader-card .spinner {
    width: 40px; height: 40px; border: 3px solid var(--border-solid);
    border-top-color: var(--accent); border-radius: 50%; animation: spin 1s linear infinite;
  }
  .loader-text { font-size: 0.9rem; color: var(--text-muted); font-weight: 500; letter-spacing: 1px; }
  @keyframes spin { to { transform: rotate(360deg); } }

  @keyframes fadeInUp {
    from { opacity: 0; transform: translateY(24px); }
    to { opacity: 1; transform: translateY(0); }
  }
  .book-card { animation: fadeInUp 0.5s ease forwards; }
  .book-card:nth-child(1) { animation-delay: 0.02s; }
  .book-card:nth-child(2) { animation-delay: 0.04s; }
  .book-card:nth-child(3) { animation-delay: 0.06s; }
  .book-card:nth-child(4) { animation-delay: 0.08s; }
  .book-card:nth-child(5) { animation-delay: 0.10s; }
  .book-card:nth-child(6) { animation-delay: 0.12s; }

  .post-feed { display: contents; }
  .post { margin: 0; }
  .comments { display: none; }
  .post-share-buttons { display: none; }
  .post-location { display: none; }
  .post-reactions { display: none; }

  .hero-carousel .splide__slide {
  transform: scale(0.92);
  filter: blur(2px);
  opacity: 0.5;
}

.hero-carousel .splide__slide.is-active {
  transform: scale(1);
  opacity: 1;
  filter: blur(0);
}

.hero-slide-link {
  max-width: 220px;
  margin: 0 auto;
}

  /* -------------------------------------------------------
    FIX: Blogger editor sering menyisipkan inline
    background-color & color pada <span>/<font>/<b> dll.
    Di dark mode ini terlihat sebagai highlight putih/abu.
    Override semua agar transparan & warna ikut tema.
  ------------------------------------------------------- */
  [data-theme="dark"] .detail-body span,
  [data-theme="dark"] .detail-body font,
  [data-theme="dark"] .detail-body p,
  [data-theme="dark"] .detail-body li,
  [data-theme="dark"] .detail-body b,
  [data-theme="dark"] .detail-body strong,
  [data-theme="dark"] .detail-body em,
  [data-theme="dark"] .detail-body i,
  [data-theme="dark"] .detail-body u,
  [data-theme="dark"] .detail-body div,
  [data-theme="dark"] .detail-body h1,
  [data-theme="dark"] .detail-body h2,
  [data-theme="dark"] .detail-body h3,
  [data-theme="dark"] .detail-body h4,
  [data-theme="dark"] .detail-body h5,
  [data-theme="dark"] .detail-body h6,
  [data-theme="dark"] .static-page .detail-body span,
  [data-theme="dark"] .static-page .detail-body font,
  [data-theme="dark"] .static-page .detail-body p,
  [data-theme="dark"] .static-page .detail-body div {
    background-color: transparent !important;
    background: transparent !important;
  }
  /* Jaga warna teks agar tetap terbaca di dark mode */
  [data-theme="dark"] .detail-body span[style*="color"],
  [data-theme="dark"] .detail-body font[color],
  [data-theme="dark"] .detail-body *[style*="color"] {
    color: var(--text-secondary) !important;
  }
  /* Pastikan teks bold/strong tetap putih */
  [data-theme="dark"] .detail-body b,
  [data-theme="dark"] .detail-body strong {
    color: var(--text) !important;
  }
  /* Kecualikan elemen yang memang butuh background */
  [data-theme="dark"] .detail-body pre,
  [data-theme="dark"] .detail-body code,
  [data-theme="dark"] .detail-body blockquote,
  [data-theme="dark"] .detail-body table,
  [data-theme="dark"] .detail-body th,
  [data-theme="dark"] .detail-body td {
    background-color: unset !important;
  }

body.script:
//

  /* ---------- Loader ---------- */
  window.addEventListener('load', function(){
    var el = document.getElementById('glassyLoader');
    if (el) el.classList.add('hide');

    /* ---------- Clean inline styles from Blogger editor ---------- */
    document.querySelectorAll('.detail-body span, .detail-body font, .detail-body p, .detail-body div').forEach(function(el){
      if (el.style && el.style.backgroundColor) el.style.backgroundColor = '';
      if (el.style && el.style.background) el.style.background = '';
      if (el.style && el.style.color && el.style.color.indexOf('rgb(0,0,0') === 0) el.style.color = '';
    });
  });

  /* ---------- Dark/Light Theme ---------- */
  var themeBtn  = document.getElementById('themeBtn');
  var themeIcon = document.getElementById('themeIcon');
  var root = document.documentElement;

  function updateThemeIcon() {
    themeIcon.innerText = root.getAttribute('data-theme') === 'light' ? 'dark_mode' : 'light_mode';
  }
  themeBtn.addEventListener('click', function() {
    var next = root.getAttribute('data-theme') === 'light' ? 'dark' : 'light';
    root.setAttribute('data-theme', next);
    try { localStorage.setItem('theme', next); } catch(e) {}
    updateThemeIcon();
  });
  updateThemeIcon();

  /* ---------- Language Toggle (ID <-> HI) ---------- */
  var i18n = {
    id: {
      loading:   'MEMUAT...',
      search:    'Cari koleksi...',
      colHead:   'Koleksi Buku',
      libCol:    'Koleksi Perpustakaan Digital',
      author:    'Penulis:',
      published: 'Dipublikasikan:',
      genre:     'Genre:',
      synopsis:  'Sinopsis & Detail Buku',
      footerText: null,
      /* --- Halaman Tentang --- */
      aboutWelcome: 'Selamat datang di <strong>Muhaimin Pustakālay</strong>, sebuah proyek perpustakaan digital pribadi yang didedikasikan untuk mengumpulkan, merapikan, dan membagikan koleksi buku pilihan. Proyek ini dibangun dengan komitmen untuk menyediakan antarmuka yang bersih, modern, dan nyaman bagi para penikmat literatur.',
      aboutQuote: '"Sebuah ruangan tanpa buku ibarat tubuh tanpa jiwa." — Marcus Tullius Cicero',
      aboutGoalsTitle: 'Tujuan Proyek',
      aboutGoalsDesc: 'Pada awalnya, ruang ini dibangun sekadar sebagai arsip pribadi untuk mendokumentasikan jejak literatur yang telah saya baca. Namun seiring berjalannya waktu, platform ini dikembangkan dan dipoles dengan gaya antarmuka <em>glassmorphism</em> (elemen menyerupai kaca) dan teknologi web kekinian agar pengalaman Anda saat menjelajahi katalog buku terasa sama menyenangkannya dengan membaca buku itu sendiri.',
      aboutFeaturesTitle: 'Fitur Platform',
      aboutFeaturesIntro: 'Kami merancang platform ini tidak hanya sekadar estetik, tapi juga berfokus pada kenyamanan navigasi:',
      aboutFeatResponsive: 'Antarmuka Responsif:',
      aboutFeatResponsiveDesc: 'Memastikan tata letak tetap rapi dan mulus, baik Anda membukanya melalui komputer, tablet, maupun layar ponsel.',
      aboutFeatTheme: 'Tema Adaptif:',
      aboutFeatThemeDesc: 'Dukungan penuh untuk mode siang (<em>Light Mode</em>) dan mode malam (<em>Dark Mode</em>) demi menjaga kesehatan mata Anda.',
      aboutFeatNav: 'Navigasi Instan:',
      aboutFeatNavDesc: 'Berkat teknologi transisi AJAX di belakang layar, perpindahan antar halaman daftar koleksi terasa instan tanpa harus melihat layar putih <em>refresh</em> memuat ulang secara utuh.',
      aboutDisclaimerTitle: 'Penafian (Disclaimer)',
      aboutDisclaimerText: 'Situs ini <strong>tidak</strong> meng-host, mengunggah, atau menyimpan file media apa pun di <em>server</em> kami. Seluruh materi, sampul, dan data buku yang ditampilkan bersumber dari tautan pihak ketiga yang tersebar bebas di internet. Apabila Anda memiliki klaim hak cipta atau meminta konten tertentu diturunkan, silakan hubungi kami untuk kami tindak lanjuti secara langsung.',
      aboutConnectTitle: 'Terhubung Bersama Kami',
      aboutConnectText: 'Punya umpan balik, laporan tautan rusak, rekomendasi koleksi buku, atau sekadar ingin menyapa? Anda dapat terhubung langsung dengan kreator di balik layar melalui platform di bawah ini:',
      btnInstagram: 'Instagram',
      btnGitHub: 'GitHub',
      /* --- Halaman Kontak --- */
      contactBio: 'Halo! Saya pengembang di balik proyek Muhaimin Pustakālay. Saya memiliki minat besar pada pengembangan web modern dan kurasi literatur digital. Jangan ragu untuk terhubung melalui platform di bawah ini.',
      labelEmail: 'Email',
      labelInstagram: 'Instagram',
      labelFacebook: 'Facebook',
      labelLinkedIn: 'LinkedIn'
    },
    hi: {
      loading:   '\u0932\u094b\u0921 \u0939\u094b \u0930\u0939\u093e \u0939\u0948...',
      search:    '\u0938\u0902\u0917\u094d\u0930\u0939 \u0916\u094b\u091c\u0947\u0902...',
      colHead:   '\u092a\u0941\u0938\u094d\u0924\u0915 \u0938\u0902\u0917\u094d\u0930\u0939',
      libCol:    '\u0921\u093f\u091c\u093f\u091f\u0932 \u092a\u0941\u0938\u094d\u0924\u0915\u093e\u0932\u092f \u0938\u0902\u0917\u094d\u0930\u0939',
      author:    '\u0932\u0947\u0916\u0915:',
      published: '\u092a\u094d\u0930\u0915\u093e\u0936\u093f\u0924:',
      genre:     '\u0935\u093f\u0927\u093e:',
      synopsis:  '\u0938\u093e\u0930\u093e\u0902\u0936 \u0914\u0930 \u092a\u0941\u0938\u094d\u0924\u0915 \u0935\u093f\u0935\u0930\u0923',
      footerText: null,
      /* --- Halaman Tentang (Hindi) --- */
      aboutWelcome: '<strong>Muhaimin Pustakālay</strong> में आपका स्वागत है, यह एक निजी डिजिटल लाइब्रेरी परियोजना है जो चयनित पुस्तकों के संग्रह को एकत्रित, व्यवस्थित और साझा करने के लिए समर्पित है। इस परियोजना को साहित्य के प्रेमियों के लिए एक स्वच्छ, आधुनिक और आरामदायक इंटरफ़ेस प्रदान करने के प्रतिबद्धता के साथ बनाया गया है।',
      aboutQuote: '"बिना किताबों के एक कमरा आत्मा के बिना एक शरीर के समान है।" — मार्कस टुलियस सिसरो',
      aboutGoalsTitle: 'परियोजना का उद्देश्य',
      aboutGoalsDesc: 'शुरुआत में, यह स्थान केवल मेरे द्वारा पढ़ी गई साहित्य की यात्रा को दस्तावेज़ करने के लिए एक व्यक्तिगत संग्रह के रूप में बनाया गया था। लेकिन समय के साथ, इस प्लेटफॉर्म को <em>glassmorphism</em> (कांच जैसे तत्व) शैली और आधुनिक वेब तकनीकों के साथ विकसित और पॉलिश किया गया, ताकि जब आप पुस्तक कैटलॉग ब्राउज़ करें तो अनुभव उतना ही सुखद हो जितना कि खुद किताब पढ़ना।',
      aboutFeaturesTitle: 'प्लेटफॉर्म की विशेषताएं',
      aboutFeaturesIntro: 'हमने इस प्लेटफॉर्म को केवल सौंदर्यशास्त्र के लिए नहीं, बल्कि नेविगेशन आराम पर भी ध्यान केंद्रित करके डिज़ाइन किया है:',
      aboutFeatResponsive: 'उत्तरदायी इंटरफ़ेस:',
      aboutFeatResponsiveDesc: 'चाहे आप इसे कंप्यूटर, टैबलेट या मोबाइल स्क्रीन के माध्यम से खोलें, लेआउट को साफ और सहज रखना सुनिश्चित करता है।',
      aboutFeatTheme: 'अनुकूली थीम:',
      aboutFeatThemeDesc: 'आपकी आंखों की सेहत के लिए <em>लाइट मोड</em> और <em>डार्क मोड</em> दोनों का पूरा समर्थन।',
      aboutFeatNav: 'त्वरित नेविगेशन:',
      aboutFeatNavDesc: 'पृष्ठभूमि में AJAX संक्रमण तकनीक के लिए धन्यवाद, संग्रह सूची के पृष्ठों के बीच संक्रमण तुरंत महसूस होता है, बिना पूर्ण <em>रिफ़्रेश</em> स्क्रीन देखे।',
      aboutDisclaimerTitle: 'अस्वीकरण (Disclaimer)',
      aboutDisclaimerText: 'यह साइट हमारे <em>सर्वर</em> पर किसी भी मीडिया फ़ाइल को होस्ट, अपलोड या संग्रहीत <strong>नहीं</strong> करती है। प्रदर्शित सभी सामग्री, कवर और पुस्तक डेटा इंटरनेट पर स्वतंत्र रूप से उपलब्ध तृतीय-पक्ष लिंक से sourced हैं। यदि आपका कोई कॉपीराइट दावा है या किसी विशिष्ट सामग्री को हटाने का अनुरोध करना चाहते हैं, तो कृपया सीधे हमसे संपर्क करें।',
      aboutConnectTitle: 'हमसे जुड़ें',
      aboutConnectText: 'कोई प्रतिक्रिया, टूटे हुए लिंक की रिपोर्ट, पुस्तक संग्रह की सिफारिश, या बस नमस्ते कहना चाहते हैं? आप नीचे दिए गए प्लेटफॉर्म के माध्यम से सीधे निर्माता से जुड़ सकते हैं:',
      btnInstagram: 'इंस्टाग्राम',
      btnGitHub: 'गिटहब',
      /* --- Halaman Kontak (Hindi) --- */
      contactBio: 'नमस्ते! मैं Muhaimin Pustakālay परियोजना के पीछे का डेवलपर हूं। मुझे आधुनिक वेब विकास और डिजिटल साहित्य क्यूरेशन में बहुत रुचि है। नीचे दिए गए प्लेटफॉर्म के माध्यम से जुड़ने में संकोच न करें।',
      labelEmail: 'ईमेल',
      labelInstagram: 'इंस्टाग्राम',
      labelFacebook: 'फेसबुक',
      labelLinkedIn: 'लिंक्डइन'
    }
  };

  /* Nav link texts by position (matches widget-settings order) */
  var navTexts = {
    id: ['Beranda', 'Koleksi', 'Tentang'],
    hi: ['\u0939\u094b\u092e', '\u0938\u0902\u0917\u094d\u0930\u0939', '\u0915\u0947 \u092c\u093e\u0930\u0947 \u092e\u0947\u0902']
  };

  /*
   * Kamus terjemahan nav: kunci = teks asli Indonesia,
   * nilai = terjemahan Hindi.
   * Tambahkan entri baru di sini jika ada menu baru.
   */
  var navDict = {
    'Beranda':     '\u0939\u094b\u092e',
    'Koleksi':     '\u0938\u0902\u0917\u094d\u0930\u0939',
    'Tentang':     '\u0915\u0947 \u092c\u093e\u0930\u0947 \u092e\u0947\u0902',
    'Kontak':      '\u0938\u0902\u092a\u0930\u094d\u0915',
    'Pustaka BSI': 'BSI \u092a\u0941\u0938\u094d\u0924\u0915\u093e\u0932\u092f'
  };

  /* Simpan teks asli nav saat halaman pertama dimuat */
  var navOriginals = [];
  document.querySelectorAll('#mainNav a').forEach(function(a) {
    navOriginals.push(a.textContent.trim());
  });

  var currentLang = 'id';

  function applyLang(lang) {
    currentLang = lang;

    /* 1. Translate all [data-i18n] elements */
    document.querySelectorAll('[data-i18n]').forEach(function(el) {
      var key = el.getAttribute('data-i18n');
      if (i18n[lang] && i18n[lang][key] !== null && i18n[lang][key] !== undefined) {
        /* Use innerHTML if content has HTML tags (<strong>, <em>, etc.), else textContent */
        if (i18n[lang][key].indexOf('<') !== -1 && i18n[lang][key].indexOf('>') !== -1) {
          el.innerHTML = i18n[lang][key];
        } else {
          el.textContent = i18n[lang][key];
        }
      }
    });

    /* 2. Translate placeholder inputs */
    document.querySelectorAll('[data-i18n-ph]').forEach(function(el) {
      var key = el.getAttribute('data-i18n-ph');
      if (i18n[lang] && i18n[lang][key]) el.placeholder = i18n[lang][key];
    });

    /* 3. Nav links — gunakan teks asli sebagai kunci, bukan posisi.
          Ini bekerja meskipun ada menu tambahan dari Dashboard. */
    document.querySelectorAll('#mainNav a').forEach(function(a, idx) {
      if (lang === 'hi') {
        var original = navOriginals[idx] || a.textContent.trim();
        a.textContent = navDict[original] || original; /* fallback ke teks asli jika tidak ada terjemahan */
      } else {
        /* Kembalikan ke teks Indonesia asli */
        if (navOriginals[idx] !== undefined) a.textContent = navOriginals[idx];
      }
    });

    /* 4. Font override via data-lang on body */
    document.body.setAttribute('data-lang', lang);
    document.documentElement.setAttribute('lang', lang);

    /* 5. Update toggle button label */
    var tag = document.getElementById('langTag');
    var btn = document.getElementById('langBtn');
    if (tag) tag.textContent = (lang === 'hi') ? 'ID' : 'HI';
    if (btn) {
      if (lang === 'hi') btn.classList.add('lang-hi');
      else btn.classList.remove('lang-hi');
    }

    /* 6. Persist */
    try { localStorage.setItem('pustakalay-lang', lang); } catch(e) {}
  }

  /* Toggle click */
  var langBtn = document.getElementById('langBtn');
  if (langBtn) {
    langBtn.addEventListener('click', function() {
      applyLang(currentLang === 'id' ? 'hi' : 'id');
    });
  }

  /* Restore saved language on page load */
  (function() {
    try {
      var saved = localStorage.getItem('pustakalay-lang');
      if (saved === 'hi') applyLang('hi');
    } catch(e) {}
  })();

  /* ---------- Mobile nav: close on outside click ---------- */
  document.addEventListener('click', function(e) {
    var nav = document.getElementById('mainNav');
    var toggleBtn = document.querySelector('.menu-toggle');
    if (nav && nav.classList.contains('active') && !nav.contains(e.target) && (!toggleBtn || !toggleBtn.contains(e.target))) {
      nav.classList.remove('active');
    }
  });

//

//
document.addEventListener("DOMContentLoaded", function() {
  var perPage = 10;
  var maxVisiblePages = 5;
  var pager = document.getElementById('blog-pager');
  if (!pager) return;

  function getPageConfig(locUrl) {
    var loc = new URL(locUrl, window.location.origin);
    var isLabel = loc.pathname.includes('/search/label/');
    var isSearch = loc.search.includes('q=');
    var feedUrl = '/feeds/posts/default?alt=json&max-results=0';
    var baseUrl = '/search?max-results=' + perPage;
    if (isLabel) {
      var label = decodeURIComponent(loc.pathname.split('/search/label/')[1].split('?')[0]);
      feedUrl = '/feeds/posts/default/-/' + encodeURIComponent(label) + '?alt=json&max-results=0';
      baseUrl = '/search/label/' + encodeURIComponent(label) + '?max-results=' + perPage;
    } else if (isSearch) {
      var q = new URLSearchParams(loc.search).get('q');
      feedUrl = '/feeds/posts/default?alt=json&q=' + encodeURIComponent(q) + '&max-results=0';
      baseUrl = '/search?q=' + encodeURIComponent(q) + '&max-results=' + perPage;
    }
    return { loc: loc, isLabel: isLabel, isSearch: isSearch, feedUrl: feedUrl, baseUrl: baseUrl };
  }

  function renderPager(locUrl) {
    var cfg = getPageConfig(locUrl);
    var params = new URLSearchParams(cfg.loc.search);
    var currentStart = parseInt(params.get('start')) || 1;
    var currentPage = Math.ceil(currentStart / perPage);
    if (cfg.loc.pathname === '/' || cfg.loc.pathname === '/index.html') currentPage = 1;

    fetch(cfg.feedUrl).then(function(r){ return r.json(); }).then(function(data) {
      var total = parseInt(data.feed.openSearch$totalResults.$t);
      var totalPages = Math.ceil(total / perPage);
      if (totalPages <= 1) { pager.style.display = 'none'; return; }
      else { pager.style.display = 'flex'; }

      var html = '';
      if (currentPage > 1) {
        var prevStart = (currentPage - 2) * perPage + 1;
        var link = (currentPage === 2 && !cfg.isLabel && !cfg.isSearch) ? '/' : cfg.baseUrl + '&start=' + prevStart;
        if (cfg.isLabel && currentPage === 2) link = cfg.baseUrl.split('?')[0];
        html += '<a href="' + link + '" class="ajax-page"><span class="material-icons">chevron_left</span></a>';
      } else {
        html += '<span style="opacity:0.3;cursor:not-allowed;"><span class="material-icons">chevron_left</span></span>';
      }
      var startPage = Math.max(1, currentPage - Math.floor(maxVisiblePages / 2));
      var endPage = startPage + maxVisiblePages - 1;
      if (endPage > totalPages) { endPage = totalPages; startPage = Math.max(1, endPage - maxVisiblePages + 1); }
      if (startPage > 1) {
        html += '<a href="' + (cfg.isLabel||cfg.isSearch ? cfg.baseUrl+'&start=1' : '/') + '" class="ajax-page">1</a>';
        if (startPage > 2) html += '<span class="page-dots">...</span>';
      }
      for (var i = startPage; i <= endPage; i++) {
        if (i === currentPage) { html += '<span class="current">' + i + '</span>'; }
        else {
          var iStart = (i - 1) * perPage + 1;
          var iLink = (i === 1 && !cfg.isLabel && !cfg.isSearch) ? '/' : cfg.baseUrl + '&start=' + iStart;
          if (cfg.isLabel && i === 1) iLink = cfg.baseUrl.split('?')[0];
          html += '<a href="' + iLink + '" class="ajax-page">' + i + '</a>';
        }
      }
      if (endPage < totalPages) {
        if (endPage < totalPages - 1) html += '<span class="page-dots">...</span>';
        html += '<a href="' + cfg.baseUrl + '&start=' + ((totalPages-1)*perPage+1) + '" class="ajax-page">' + totalPages + '</a>';
      }
      if (currentPage < totalPages) {
        html += '<a href="' + cfg.baseUrl + '&start=' + (currentPage * perPage + 1) + '" class="ajax-page"><span class="material-icons">chevron_right</span></a>';
      } else {
        html += '<span style="opacity:0.3;cursor:not-allowed;"><span class="material-icons">chevron_right</span></span>';
      }
      pager.innerHTML = html;
    }).catch(function(e){ console.error('Paginasi error:', e); });
  }

  renderPager(window.location.href);

  function renderPosts(entries) {
    var html = '';
    entries.forEach(function(entry) {
      var title = entry.title.$t;
      var url = entry.link.find(function(l){ return l.rel === 'alternate'; }).href;
      var img = '';
      if (entry.media$thumbnail) { img = entry.media$thumbnail.url; }
      else if (entry.content && entry.content.$t) {
        var m = entry.content.$t.match(/<img[^>]+src=(['"])(.*?)\1/i);
        if (m) img = m[2];
      }
      if (img) {
        img = img.replace(/\/s[0-9]+[^\/]*\//, '/w400/');
        img = img.replace(/\=s[0-9]+[a-zA-Z0-9\-]*/, '=w400');
      }
      var label = entry.category ? entry.category[0].term : '';
      html += '<article class="book-card"><a class="card-link" href="' + url + '"><div class="card-image">';
      if (img) {
        html += '<img alt="' + title + '" src="' + img + '" loading="lazy"/>';
      } else {
        html += '<img alt="Tidak Ada Cover" src="data:image/svg+xml,%3Csvg xmlns=%22http://www.w3.org/2000/svg%22 width=%22400%22 height=%22600%22%3E%3Crect fill=%22%2315161a%22 width=%22400%22 height=%22600%22/%3E%3Ctext fill=%22%23747d8c%22 font-family=%22sans-serif%22 font-size=%2220%22 dy=%2210.5%22 x=%2250%25%22 y=%2250%25%22 text-anchor=%22middle%22%3ETidak Ada Cover%3C/text%3E%3C/svg%3E"/>';
      }
      html += '<div class="card-overlay"><h2 class="card-title">' + title + '</h2></div>';
      if (label) html += '<span class="card-badge" data-label="' + label + '">' + label + '</span>';
      html += '</div></a></article>';
    });
    return html;
  }

  pager.addEventListener('click', function(e) {
    var link = e.target.closest('a.ajax-page');
    if (!link) return;
    e.preventDefault();
    var url = link.href;
    var loader = document.getElementById('glassyLoader');
    if (loader) loader.classList.remove('hide');
    var cfg = getPageConfig(url);
    var params = new URLSearchParams(cfg.loc.search);
    var start = params.get('start') || 1;
    var fetchUrl = cfg.feedUrl.replace('max-results=0', 'max-results=' + perPage + '&start-index=' + start);
    fetch(fetchUrl).then(function(r){ return r.json(); }).then(function(data) {
      var entries = data.feed.entry || [];
      document.querySelector('.book-grid').innerHTML = renderPosts(entries);
      window.history.pushState({ path: url }, '', url);
      renderPager(url);
      var hero = document.getElementById('heroCarousel');
      var divider = document.querySelector('.section-divider');
      if (start > 1 || cfg.isLabel || cfg.isSearch) {
        if (hero) hero.style.display = 'none';
        if (divider) divider.style.display = 'none';
      } else {
        if (hero) hero.style.display = 'block';
        if (divider) divider.style.display = 'block';
      }
      window.scrollTo({ top: document.querySelector('.site-main').offsetTop - 20, behavior: 'smooth' });
      if (loader) setTimeout(function(){ loader.classList.add('hide'); }, 400);
    }).catch(function(err){
      console.error(err);
      window.location.href = url;
    });
  });
});
