document.addEventListener("DOMContentLoaded", function() {
  var heroEl = document.getElementById('heroCarousel');
  if (heroEl) {
    new Splide(heroEl, {
      type: 'loop',
      focus: 'center',
      perPage: 5,
      gap: '20px',
      autoplay: true,
      interval: 3500,
      speed: 800,
      updateOnMove: true,
      pagination: false,
      arrows: false,
      breakpoints: {
        1200: { perPage: 4, gap: '16px' },
        992:  { perPage: 3, gap: '16px' },
        768:  { perPage: 3, gap: '12px' },
        480:  { perPage: 2, gap: '10px' }
      }
    }).mount();
  }
});
